
// ==============================================================================
// 🤖 OPTIMIZED GREEDY MATCH-3 BATTLE BOT (ADVANCED CASCADE HEURISTICS)
// ==============================================================================

(function() {
    let botGameLogic = null;
    let botIsRunning = false;

    // 1. Safely intercept the GameLogic reference before the game initializes
    if (typeof plato !== 'undefined' && !plato._botHooked) {
        plato._botHooked = true;
        const originalSetGameLogic = plato.setGameLogic;
        
        plato.setGameLogic = function(logic) {
            botGameLogic = logic;
            
            if (!botIsRunning) {
                botIsRunning = true;
                plato.setTimer(botTick, 500, true);
                plato.log("[Bot] Advanced Cascade-Biased AI Initialized!", 2);
            }
            return originalSetGameLogic.apply(this, arguments);
        };
    }

    // 2. Main Bot Loop
    function botTick() {
        if (!botGameLogic) return;
        
        // Strict Execution Checks
        if (botGameLogic.gamePhase !== 3) return;
        if (!botGameLogic.isLocalTurn()) return;
        if (botGameLogic.gameOver) return;

        let mySeat = botGameLogic.localSeat;
        if (mySeat === undefined || mySeat < 0) return;

        let pState = botGameLogic.playerStates[mySeat];

        // Priority 1: Evolve or Boost
        for (let i = 0; i < pState.monsterStates.length; i++) {
            if (botGameLogic.canEvolveMonster(mySeat, i)) {
                botGameLogic.localMove({ t: 7, mi: i });
                return;
            }
            if (botGameLogic.canBoostMonster(mySeat, i)) {
                botGameLogic.localMove({ t: 8, mi: i });
                return;
            }
        }

        // Resolve Elements
        const getElements = (seat) => {
            let elements = [];
            for (let i = 0; i < 2; i++) {
                try {
                    let monster = botGameLogic.getMonster(seat, i);
                    if (monster && monster.tileType) {
                        elements.push(monster.tileType);
                    }
                } catch (e) {}
            }
            return elements;
        };

        let myElements = getElements(mySeat);
        let oppElements = getElements(mySeat === 0 ? 1 : 0);

        // Priority 2: Execute Best Move
        const move = getBestMove(botGameLogic, myElements, oppElements);
        if (move) {
            botGameLogic.localMove({
                t: 6, // SwapTiles
                x1: move.x1,
                y1: move.y1,
                x2: move.x2,
                y2: move.y2
            });
        }
    }

    // 3. Advanced Heuristic Algorithm
    function getBestMove(logic, myElements, oppElements) {
        myElements = myElements || [];
        oppElements = oppElements || [];

        if (!logic || !logic.board || !logic.board.tiles) return null;

        const rows = logic.board.height; 
        const cols = logic.board.width;  
        const originalGrid = logic.board.tiles;
        const originalEffects = logic.board.effects;

        // Check if board is tumbling
        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
                if (originalGrid[y][x] === 0) return null; 
            }
        }

        const cloneGrid = () => {
            const newGrid = new Array(rows);
            for (let y = 0; y < rows; y++) {
                newGrid[y] = new Array(cols);
                for (let x = 0; x < cols; x++) {
                    newGrid[y][x] = originalGrid[y][x];
                }
            }
            return newGrid;
        };

        // Extracts matches WITH orientation and depth profiling
        const findMatches = (grid) => {
            let matches = [];

            // Horizontal
            for (let y = 0; y < rows; y++) {
                let matchLength = 1;
                for (let x = 1; x < cols; x++) {
                    if (grid[y][x] !== 0 && grid[y][x] !== 7 && grid[y][x] === grid[y][x - 1]) {
                        matchLength++;
                    } else {
                        if (matchLength >= 3) matches.push({ type: grid[y][x - 1], length: matchLength, isHorizontal: true, depth: y });
                        matchLength = 1;
                    }
                }
                if (matchLength >= 3) matches.push({ type: grid[y][cols - 1], length: matchLength, isHorizontal: true, depth: y });
            }

            // Vertical
            for (let x = 0; x < cols; x++) {
                let matchLength = 1;
                for (let y = 1; y < rows; y++) {
                    if (grid[y][x] !== 0 && grid[y][x] !== 7 && grid[y][x] === grid[y - 1][x]) {
                        matchLength++;
                    } else {
                        if (matchLength >= 3) matches.push({ type: grid[y - 1][x], length: matchLength, isHorizontal: false, depth: y - 1 });
                        matchLength = 1;
                    }
                }
                if (matchLength >= 3) matches.push({ type: grid[rows - 1][x], length: matchLength, isHorizontal: false, depth: rows - 1 });
            }

            return matches;
        };

        if (findMatches(originalGrid).length > 0) return null;

        // ADVANCED SCORER
        const evaluateScore = (matches) => {
            let score = 0;
            
            // CROSS/COMBO MULTIPLIER: If one swap causes multiple matches (L-shape/T-shape)
            if (matches.length > 1) score += 600;

            for (let i = 0; i < matches.length; i++) {
                const match = matches[i];
                
                // EXTRA MOVE ABSOLUTE DOMINANCE (4+ matches)
                if (match.length >= 5) score += 8000;
                else if (match.length === 4) score += 3000;
                else if (match.length === 3) score += 50;

                // CASCADE FOOTPRINT (Horizontal clears 3 columns vs Vertical's 1 column)
                if (match.isHorizontal) score += 80;

                // GRAVITY DEPTH BIAS (Matches at the bottom cause more blocks to fall)
                score += (match.depth * 5);

                // COMBAT ADVANTAGE
                if (myElements.indexOf(match.type) !== -1) score += 200;
                else if (oppElements.indexOf(match.type) !== -1) score += 150;
                
                // BERRIES
                if (match.type === 6) score += 100;
            }
            return score;
        };

        const isImmovable = (x, y) => {
            if (!originalEffects || !originalEffects[y] || !originalEffects[y][x]) return false;
            const fx = originalEffects[y][x];
            return fx.indexOf(2) !== -1 || fx.indexOf(8) !== -1;
        };

        const grid = cloneGrid();
        const swap = (x1, y1, x2, y2) => {
            const temp = grid[y1][x1];
            grid[y1][x1] = grid[y2][x2];
            grid[y2][x2] = temp;
        };

        let bestScore = -1;
        let bestMove = null;

        // Horizontal Swaps
        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols - 1; x++) {
                if (grid[y][x] === grid[y][x + 1]) continue;
                if (isImmovable(x, y) || isImmovable(x + 1, y)) continue;

                swap(x, y, x + 1, y);
                const matches = findMatches(grid);
                if (matches.length > 0) {
                    const score = evaluateScore(matches);
                    if (score > bestScore) {
                        bestScore = score;
                        bestMove = { x1: x, y1: y, x2: x + 1, y2: y };
                    }
                }
                swap(x, y, x + 1, y);
            }
        }

        // Vertical Swaps
        for (let y = 0; y < rows - 1; y++) {
            for (let x = 0; x < cols; x++) {
                if (grid[y][x] === grid[y + 1][x]) continue;
                if (isImmovable(x, y) || isImmovable(x, y + 1)) continue;

                swap(x, y, x, y + 1);
                const matches = findMatches(grid);
                if (matches.length > 0) {
                    const score = evaluateScore(matches);
                    if (score > bestScore) {
                        bestScore = score;
                        bestMove = { x1: x, y1: y, x2: x, y2: y + 1 };
                    }
                }
                swap(x, y, x, y + 1);
            }
        }

        return bestMove; 
    }
})();

