// ==============================================================================
// 🤖 OPTIMIZED GREEDY MATCH-3 BATTLE BOT (SAFE GLOBAL HOOK v4)
// ==============================================================================

(function() {
    let botGameLogic = null;
    let botIsRunning = false;
    let botWaitUntil = 0;

    // 1. Safely intercept the GameLogic reference before the game initializes
    if (typeof plato !== 'undefined' && !plato._botHooked) {
        plato._botHooked = true;
        const originalSetGameLogic = plato.setGameLogic;
        
        plato.setGameLogic = function(logic) {
            botGameLogic = logic;
            
            if (!botIsRunning) {
                botIsRunning = true;
                // Run bot logic every 500ms safely in the background
                plato.setTimer(botTick, 500, true);
                plato.log("[Bot] Advanced Cascade-Biased AI Globally Hooked & Active!", 2);
            }
            return originalSetGameLogic.apply(this, arguments);
        };
    }

    // 2. Main Bot Loop
    function botTick() {
        if (!botGameLogic) return;
        
        // Pacing Check: Wait for previous animations to finish before evaluating the board
        if (Date.now() < botWaitUntil) return;

        // Strict Execution Checks: Only act in the Combat Phase (Phase 3)
        if (botGameLogic.gamePhase !== 3) return;
        if (!botGameLogic.isLocalTurn()) return;
        if (botGameLogic.gameOver) return;

        // Wait for active tumbling cascades or engine sequence resolutions
        if (botGameLogic.cascadeCount !== 0 || botGameLogic.moveMade) {
            botWaitUntil = Date.now() + 1000;
            return;
        }

        let mySeat = botGameLogic.localSeat;
        if (mySeat === undefined || mySeat < 0) return;

        let pState = botGameLogic.playerStates[mySeat];

        // Priority 1: Evolve or Boost Monsters instantly if berries are capped
        for (let i = 0; i < pState.monsterStates.length; i++) {
            if (botGameLogic.canEvolveMonster(mySeat, i)) {
                botWaitUntil = Date.now() + 1500; // Pause bot for UI animation
                botGameLogic.localMove({ t: 7, mi: i }); // MoveType.EvolveMonster
                return;
            }
            if (botGameLogic.canBoostMonster(mySeat, i)) {
                botWaitUntil = Date.now() + 1500;
                botGameLogic.localMove({ t: 8, mi: i }); // MoveType.BoostMonster
                return;
            }
        }

        // Resolve Player and Opponent Elements natively via the logic's helper
        const getElements = (seat) => {
            let elements = [];
            for (let i = 0; i < 2; i++) {
                try {
                    let monster = botGameLogic.getMonster(seat, i);
                    if (monster && monster.tileType) {
                        elements.push(monster.tileType);
                    }
                } catch (e) {}
            }
            return elements;
        };

        let myElements = getElements(mySeat);
        let oppElements = getElements(mySeat === 0 ? 1 : 0);

        // Priority 2: Determine & Execute Best Immediate Swap
        const move = getBestMove(botGameLogic, myElements, oppElements);
        if (move) {
            botWaitUntil = Date.now() + 1000; // PAUSE BOT to allow action queue to fully drain and animate
            botGameLogic.localMove({
                t: 6, // MoveType.SwapTiles
                x1: move.x1,
                y1: move.y1,
                x2: move.x2,
                y2: move.y2
            });
        }
    }

    // 3. Core Greedy Match-3 Move Selection & Sandbox Simulation
    function getBestMove(logic, myElements, oppElements) {
        myElements = myElements || [];
        oppElements = oppElements || [];

        if (!logic || !logic.board || !logic.board.tiles) return null;

        const rows = logic.board.height; 
        const cols = logic.board.width;  
        const originalGrid = logic.board.tiles;
        const originalEffects = logic.board.effects;

        // Check if board is tumbling (empty tiles exist). If so, wait.
        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
                if (originalGrid[y][x] === 0) return null; 
            }
        }

        // Deep Clone implementation to isolate our evaluation board securely
        const cloneGrid = () => {
            const newGrid = new Array(rows);
            for (let y = 0; y < rows; y++) {
                newGrid[y] = new Array(cols);
                for (let x = 0; x < cols; x++) {
                    newGrid[y][x] = originalGrid[y][x];
                }
            }
            return newGrid;
        };

        // Extracts and identifies lengths of resulting matches 
        const findMatches = (grid) => {
            let matches = [];

            // Horizontal Traversal
            for (let y = 0; y < rows; y++) {
                let matchLength = 1;
                for (let x = 1; x < cols; x++) {
                    // Ignore empty (0) and bomb (7) tiles
                    if (grid[y][x] !== 0 && grid[y][x] !== 7 && grid[y][x] === grid[y][x - 1]) {
                        matchLength++;
                    } else {
                        if (matchLength >= 3) matches.push({ type: grid[y][x - 1], length: matchLength, horiz: true, d: y });
                        matchLength = 1;
                    }
                }
                if (matchLength >= 3) matches.push({ type: grid[y][cols - 1], length: matchLength, horiz: true, d: y });
            }

            // Vertical Traversal
            for (let x = 0; x < cols; x++) {
                let matchLength = 1;
                for (let y = 1; y < rows; y++) {
                    if (grid[y][x] !== 0 && grid[y][x] !== 7 && grid[y][x] === grid[y - 1][x]) {
                        matchLength++;
                    } else {
                        if (matchLength >= 3) matches.push({ type: grid[y - 1][x], length: matchLength, horiz: false, d: y - 1 });
                        matchLength = 1;
                    }
                }
                if (matchLength >= 3) matches.push({ type: grid[rows - 1][x], length: matchLength, horiz: false, d: rows - 1 });
            }

            return matches;
        };

        // If the live board naturally has resting matches somehow, wait for the engine to resolve them.
        if (findMatches(originalGrid).length > 0) return null;

        // Tactical Match Scorer
        const evaluateScore = (matches) => {
            let score = 0;

            // CROSS/COMBO MULTIPLIER: If one swap causes multiple matches (L-shape/T-shape cross)
            if (matches.length > 1) score += 600;

            for (let i = 0; i < matches.length; i++) {
                const m = matches[i];
                
                // EXTRA MOVE ABSOLUTE DOMINANCE (4+ matches)
                if (m.length >= 5) score += 8000;
                else if (m.length === 4) score += 3000;
                else if (m.length === 3) score += 50;

                // CASCADE FOOTPRINT (Horizontal clears 3 columns vs Vertical's 1 column)
                if (m.horiz) score += 80;

                // GRAVITY DEPTH BIAS (Matches at the bottom cause more blocks to fall)
                score += (m.d * 5);

                // Contextual combat advantage weights (Safely using indexOf instead of includes)
                if (myElements.indexOf(m.type) !== -1) score += 200;
                else if (oppElements.indexOf(m.type) !== -1) score += 150;
                
                // Berries sustain evolves & heals
                if (m.type === 6) score += 100;
            }
            return score;
        };

        // STRICT IMMOVABLE CHECKER: Ensures we don't grab Frozen/Blackhole tiles
        const isImmovable = (x, y) => {
            if (!originalEffects || !originalEffects[y] || !originalEffects[y][x]) return false;
            const fx = originalEffects[y][x];
            // ID 2 = Frozen, ID 8 = Blackhole
            return fx.indexOf(2) !== -1 || fx.indexOf(8) !== -1;
        };

        const grid = cloneGrid();
        
        const swap = (x1, y1, x2, y2) => {
            const temp = grid[y1][x1];
            grid[y1][x1] = grid[y2][x2];
            grid[y2][x2] = temp;
        };

        let bestScore = -1;
        let bestMove = null;

        // Simulate all legal Horizontal Swaps
        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols - 1; x++) {
                if (grid[y][x] === grid[y][x + 1]) continue;
                
                // Strictly check for immovable properties natively before attempting to grab
                if (isImmovable(x, y) || isImmovable(x + 1, y)) continue;

                swap(x, y, x + 1, y);
                
                const matches = findMatches(grid);
                if (matches.length > 0) {
                    const score = evaluateScore(matches);
                    if (score > bestScore) {
                        bestScore = score;
                        bestMove = { x1: x, y1: y, x2: x + 1, y2: y };
                    }
                }
                
                swap(x, y, x + 1, y); // Safe Revert
            }
        }

        // Simulate all legal Vertical Swaps
        for (let y = 0; y < rows - 1; y++) {
            for (let x = 0; x < cols; x++) {
                if (grid[y][x] === grid[y + 1][x]) continue;

                if (isImmovable(x, y) || isImmovable(x, y + 1)) continue;

                swap(x, y, x, y + 1);
                
                const matches = findMatches(grid);
                if (matches.length > 0) {
                    const score = evaluateScore(matches);
                    if (score > bestScore) {
                        bestScore = score;
                        bestMove = { x1: x, y1: y, x2: x, y2: y + 1 };
                    }
                }
                
                swap(x, y, x, y + 1); // Safe Revert
            }
        }

        return bestMove; 
    }
})();

